}

function useCreateOrder() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: createOrder,
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['orders'] });  // prefix match
      qc.invalidateQueries({ queryKey: ['user', 'balance'] });
      qc.invalidateQueries({ queryKey: ['activity', 'recent'] });
    }
  });
}

