// scripts/validate-contrast.ts
import { tokens } from './src/tokens';
import { getContrastRatio } from 'color2k';

const pairs = [
  { fg: tokens.color.text.primary, bg: tokens.color.surface, min: 7 },  // AAA body
  { fg: tokens.color.text.muted, bg: tokens.color.surface, min: 4.5 },  // AA secondary
  { fg: tokens.color.action.primary.text, bg: tokens.color.action.primary.bg, min: 4.5 }
];

for (const { fg, bg, min } of pairs) {
  const ratio = getContrastRatio(fg, bg);
  if (ratio < min) console.error(`Fail: ${fg} on ${bg}: ${ratio}, need ${min}`);
}

