import { useForm, useWatch } from 'react-hook-form';
import { useEffect } from 'react';

function useDebouncedAutoSave<T>(values: T) {
  useEffect(() => {
    const id = setTimeout(() => {
      void fetch('/api/settings', { method: 'POST', body: JSON.stringify(values) });
    }, 800);
    return () => clearTimeout(id);
  }, [values]);
}

function SettingsForm() {
  const { register, control } = useForm({ defaultValues });
  const values = useWatch({ control });
  useDebouncedAutoSave(values);
  return (
    <form>
      {Array.from({ length: 30 }).map((_, i) => (
        <input key={i} {...register(`field${i}` as any)} />
      ))}
    </form>
  );
}

